# build_context_snapshot — rich text snapshot from DB
# ══════════════════════════════════════════════════════════════════════════════

class TestBuildContextSnapshot:
    def test_returns_string(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        assert isinstance(result, str)

    def test_not_empty_with_data(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        assert len(result) > 100

    def test_empty_db_returns_no_data_message(self, db):
        result = build_context_snapshot(conn=db)
        assert isinstance(result, str)
        assert "no hay" in result.lower() or len(result) < 200

    def test_contains_month_info(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        assert "2025" in result

    def test_contains_merchant_data(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        # At least one of the seeded merchants should appear
        assert any(m in result for m in ("Rappi", "Netflix", "RAPPI", "NETFLIX", "Spotify"))

    def test_contains_financial_amounts(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        # COP amounts should be visible (formatted numbers)
        assert "COP" in result or "cop" in result.lower() or "$" in result or "000" in result

    def test_contains_category_breakdown(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        # Category section should be present
        assert "Comida" in result or "categor" in result.lower()

    def test_contains_subscription_section(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        # Subscriptions section — Netflix/Spotify appear in 3 months
        assert "Netflix" in result or "Spotify" in result or "suscripc" in result.lower()

    def test_result_is_markdown(self, populated_db):
        result = build_context_snapshot(conn=populated_db)
        # Should contain markdown table or headers
        assert "#" in result or "|" in result


