from tools.chat.assistant import ChatAssistant


class TestChatAssistant:
    def _make_assistant(self, db):
        return ChatAssistant(conn=db)

    def test_instantiates(self, populated_db):
        assistant = self._make_assistant(populated_db)
        assert assistant is not None

    def test_chat_returns_dict(self, populated_db):
        fake_resp = MagicMock()
        fake_resp.content = [MagicMock(text="Tu gasto fue $115,800 COP en octubre.", type="text")]
        fake_resp.stop_reason = "end_turn"

        with patch("anthropic.Anthropic") as MockSync, \
             patch("anthropic.AsyncAnthropic") as MockAsync:
            sync_client = MagicMock()
            sync_client.messages.create.return_value = fake_resp
            MockSync.return_value = sync_client
            MockAsync.return_value = MagicMock()

            assistant = self._make_assistant(populated_db)
            result = assistant.chat("¿Cuánto gasté en octubre?")

        assert isinstance(result, dict)

    def test_chat_has_answer_key(self, populated_db):
        fake_resp = MagicMock()
        fake_resp.content = [MagicMock(text="Respuesta de prueba.", type="text")]
        fake_resp.stop_reason = "end_turn"

        with patch("anthropic.Anthropic") as MockClient:
            client = MagicMock()
            client.messages.create.return_value = fake_resp
            MockClient.return_value = client

            assistant = self._make_assistant(populated_db)
