    def test_multiple_turns_dont_crash(self, populated_db):
        fake_resp = MagicMock()
        fake_resp.content = [MagicMock(text="Ok.", type="text")]
        fake_resp.stop_reason = "end_turn"

        with patch("anthropic.Anthropic") as MockClient:
            client = MagicMock()
